#include<bits/stdc++.h>
using namespace std;
int main() {
	string a[1001];
	int n,b;
	bool w,x,y,z;
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>a[i];
	}for(int i=0;i<n;i++){
	w=1;
			x=1;
			y=1;
			z=1;

			for(int j=0;j<a[i].size();j++){
					b=a[i][j];
					if(b-'0'-7>=10){
						z=0;
					}if(b-'0'>=10){
						x=0;
					}if(b-'0'>=8){
						y=0;
					}if(b-'0'>=2){
						w=0;
					}
					}
			cout<<w<<" "<<y<<" "<<x<<" "<<z<<endl;
			}

	return 0;
}
